// Parse routing configuration and determine destinations
const routingConfig = $input.all();
const lead = $input.first().json;

// Initialize routing rules with defaults
let routingRules = {
  destinations: [],
  minScore: 0,
  autoRoute: false
};

// Parse config values
routingConfig.forEach(config => {
  const key = config.json.config_key;
  const value = config.json.config_value;

  if (key === 'routing_destinations') {
    routingRules.destinations = JSON.parse(value);
  } else if (key === 'routing_min_score') {
    routingRules.minScore = parseInt(value) || 0;
  } else if (key === 'routing_auto') {
    routingRules.autoRoute = value === 'true';
  }
});

// Determine if lead should be routed
const shouldRoute = lead.lead_score >= routingRules.minScore && routingRules.autoRoute;

return [{
  json: {
    lead: lead,
    routingRules: routingRules,
    shouldRoute: shouldRoute,
    destinations: shouldRoute ? routingRules.destinations : []
  }
}];

// Route lead to specific destination
const lead = $input.first().json.lead;
const destination = $input.first().json.routingRules.destinations[$input.first().json.$index];

const destinationType = destination.type;
const destinationConfig = destination.config;

let result = {
  lead_id: lead.lead_id,
  destination_type: destinationType,
  status: 'pending',
  message: ''
};

try {
  switch(destinationType) {
    case 'webhook':
      // Prepare webhook payload
      const webhookPayload = {
        lead_id: lead.lead_id,
        client_id: lead.client_id,
        email: lead.email,
        first_name: lead.first_name,
        last_name: lead.last_name,
        company: lead.company,
        phone: lead.phone,
        lead_score: lead.lead_score,
        company_industry: lead.company_industry,
        company_size: lead.company_size
      };

      // This would be an actual HTTP request in production
      result.message = 'Webhook call would be made to: ' + destinationConfig.url;
      result.payload = webhookPayload;
      break;

    case 'email':
      result.message = 'Email would be sent to: ' + destinationConfig.recipient;
      result.recipient = destinationConfig.recipient;
      break;

    case 'slack':
      result.message = 'Slack message would be sent to: ' + destinationConfig.channel;
      result.channel = destinationConfig.channel;
      break;

    default:
      result.status = 'failed';
      result.message = 'Unknown destination type: ' + destinationType;
  }

  if (result.status !== 'failed') {
    result.status = 'sent';
  }

} catch (error) {
  result.status = 'failed';
  result.message = error.message;
}

return [{ json: result }];
